function stripParentheses(value: string) {
  return value.replace(/\([^)]*\)/g, '')
}

function normalizeToken(value: string) {
  return value.replace(/\s+/g, '').trim()
}

function tokenAliases(value: string) {
  const trimmed = normalizeToken(value)
  if (!trimmed) return []

  const aliases = new Set<string>([trimmed, stripParentheses(trimmed)])
  const bracketMatch = trimmed.match(/\(([^)]*)\)/)
  if (bracketMatch?.[1]) aliases.add(normalizeToken(bracketMatch[1]))

  return [...aliases].filter(Boolean)
}

function tokensMatch(input: string, condition: string) {
  const inputAliases = tokenAliases(input)
  const conditionAliases = tokenAliases(condition)
  return inputAliases.some((alias) => conditionAliases.includes(alias))
}

function findByConditions(
  section: CompatibilitySection,
  maleToken: string,
  femaleToken: string,
): CompatibilityCopyItem | null {
  const sectionCopy = COMPATIBILITY_COPY[section]
  for (const item of Object.values(sectionCopy)) {
    if (tokensMatch(maleToken, item.maleCondition) && tokensMatch(femaleToken, item.femaleCondition)) {
      return item
    }
  }
  return null
}

export function getCompatibilityCopy(
  section: CompatibilitySection,
  copyKey: string,
): CompatibilityCopyItem | null {
  const sectionCopy = COMPATIBILITY_COPY[section]
  const direct = sectionCopy[copyKey]
  if (direct) return direct

  const [maleToken, femaleToken] = copyKey.split('|')
  if (maleToken && femaleToken) {
    const byConditions = findByConditions(section, maleToken, femaleToken)
    if (byConditions) return byConditions
  }

  return null
}



